mapper.select:
SELECT * FROM help_request
WHERE status = #{status}
AND (
    6371 * acos(
        cos(radians(#{lat})) * cos(radians(latitude)) * cos(radians(longitude) - radians(#{lng}))
        + sin(radians(#{lat})) * sin(radians(latitude))
    )
) <= #{radiusKm}
ORDER BY publish_time DESC
LIMIT #{limit}
